package com.socialblog.comment.api;import com.socialblog.comment.api.CommentDtos.*;import com.socialblog.comment.application.CommentService;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.util.UUID;
@RestController @RequestMapping("/api/v1/comments")public class CommentController{private final CommentService service;public CommentController(CommentService s){service=s;}@GetMapping("/articles/{articleId}")Page<Response>article(@PathVariable UUID articleId,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="50")int size){return service.article(articleId,PageRequests.of(page,size,100));}@PostMapping ResponseEntity<Response>create(@AuthenticationPrincipal Jwt j,@Valid @RequestBody CreateRequest r){return ResponseEntity.status(201).body(service.create(user(j),r));}@PutMapping("/{id}")Response update(@PathVariable UUID id,@AuthenticationPrincipal Jwt j,@Valid @RequestBody UpdateRequest r){return service.update(id,user(j),r);}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)void delete(@PathVariable UUID id,@AuthenticationPrincipal Jwt j){service.delete(id,user(j));}private UUID user(Jwt j){return UUID.fromString(j.getSubject());}}
